import java.util.*;
public class Main{public static void main(String[] args)throws Exception{BufferedReader br=new BufferedReader(new InputStreamReader(System.in));int n=Integer.parseInt(br.readLine());StringTokenizer st=new StringTokenizer(br.readLine());int maxLen=0,cur=0;for(int i=0;i<n;i++){int x=Integer.parseInt(st.nextToken());if(x==0) cur=0; else cur++; if(cur>maxLen) maxLen=cur;} System.out.println(maxLen);}}

