import sys
def main():
 data=list(map(int,sys.stdin.read().strip().split()))
 if not data:
  return
 idx=0
 n=data[idx];idx+=1
 maxLen=cur=0
 for _ in range(n):
  x=data[idx];idx+=1
  if x==0:
   cur=0
  else:
   cur+=1
  if cur>maxLen:
   maxLen=cur
 sys.stdout.write(str(maxLen)+'\n')
if __name__=='__main__':
 main()
